args.sparql:
SELECT ?player WHERE {
  ?player wdt:P154 wd:Q320476 .
  ?player wdt:P580 ?start .
  FILTER (YEAR(?start) <= 2012)
  FILTER (?player != wd:Q207983)
}

SELECT ?player ?playerLabel WHERE {
  ?player wdt:P154 wd:Q320476 ;
          wdt:P580 ?startBucs.
  FILTER (YEAR(?startBucs) <= 2022)
  OPTIONAL { ?player wdt:P582 ?endBucs . }
  FILTER (!BOUND(?endBucs) || YEAR(?endBucs) > 2022)
  ?player wdt:P580 ?startCareer.
  FILTER (YEAR(?startCareer) <= 2011)
  FILTER (?player != wd:Q207983)
  ?player rdfs:label ?playerLabel .
  FILTER (LANG(?playerLabel) = "en")
}

SELECT ?player ?playerLabel WHERE {
  ?player wdt:P154 wd:Q320476 ;
          wdt:P580 ?startBucs.
  FILTER (YEAR(?startBucs) <= 2022)
  OPTIONAL { ?player wdt:P582 ?endBucs . }
  FILTER (!BOUND(?endBucs) || YEAR(?endBucs) >= 2022)

  ?player wdt:P154 ?team.
  ?team wdt:P580 ?startDate.
  FILTER (YEAR(?startDate) <= 2011)

  FILTER NOT EXISTS {
    ?player wdt:P154 ?otherTeam;
            wdt:P580 ?otherDate.
    FILTER (?otherDate < ?startDate)
  }

  FILTER (?player != wd:Q207983)
  ?player rdfs:label ?playerLabel.
  FILTER (LANG(?playerLabel) = "en")
}

SELECT ?player ?playerLabel WHERE {
  ?player p:P154 ?bucsStatement.
  ?bucsStatement ps:P154 wd:Q320476;
              pq:P580 ?bucsStart.
  FILTER (YEAR(?bucsStart) <= 2022)
  OPTIONAL { ?bucsStatement pq:P582 ?bucsEnd. }
  FILTER (!BOUND(?bucsEnd) || YEAR(?bucsEnd) >= 2022)

  ?player p:P154 ?careerStatement.
  ?careerStatement pq:P580 ?careerStart.

  FILTER (?player != wd:Q207983)

  GROUP BY ?player
  HAVING (MIN(YEAR(?careerStart)) <= 2011)

  OPTIONAL {
    ?player rdfs:label ?playerLabel.
    FILTER (LANG(?playerLabel) = "en")
  }
}

