  FILTER (!BOUND(?bucsEnd) || YEAR(?bucsEnd) >= 2022)

  ?player p:P154 ?careerStmt.
  ?careerStmt pq:P580 ?careerStart.
  FILTER (?player != wd:Q207983)

  OPTIONAL {
    ?player rdfs:label ?playerLabel.
    FILTER (LANG(?playerLabel) = "en")
  }
}
GROUP BY ?player ?playerLabel
HAVING (MIN(YEAR(?careerStart)) <= 2011)

SELECT DISTINCT ?player ?playerLabel WHERE {
  ?player p:P154 ?bucsStmt;
          ps:P154 wd:Q320476;
          pq:P580 ?bucsStart.
  FILTER (YEAR(?bucsStart) <= 2022)
  OPTIONAL { ?bucsStmt pq:P582 ?bucsEnd. }
  FILTER (!BOUND(?bucsEnd) || YEAR(?bucsEnd) >= 2022)

  ?player p:P154 ?careerStmt;
          pq:P580 ?careerStart.

  {
    SELECT ?player (MIN(YEAR(?careerStart)) AS ?minYear)
    WHERE {
      ?player p:P154 ?careerStmt;
              pq:P580 ?careerStart.
    }
    GROUP BY ?player
    HAVING (MIN(YEAR(?careerStart)) <= 2011)
  }

  FILTER (?player != wd:Q207983)

  OPTIONAL {
    ?player rdfs:label ?playerLabel.
    FILTER (LANG(?playerLabel) = "en")
  }
}

